        reflection: {
          child: 'God always forgives you when you say sorry with your heart. Is there something you want to tell God sorry for right now?',
          youth: 'Is there a sin or failure you have been afraid to bring to God? What would change if you truly believed nothing is beyond his mercy?',
          adult: 'When did you last receive the sacrament of Reconciliation, and what keeps you from the mercy Christ is holding open for you there?',
        },
        activity: {
          child: 'Before bed, tell God one thing you are sorry for and one thing you are thankful for, and let him hug your heart.',
          youth: 'Make a simple examination of conscience tonight and plan to go to Confession soon; write the date you will go.',
          adult: 'Make an examination of conscience today and schedule Confession this week; also extend to one person the forgiveness you hope to receive.',
        },
